#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int S[101], D[101];
        for(int i=0;i<N;i++) scanf("%d",&S[i]);
        for(int i=0;i<N;i++) scanf("%d",&D[i]);
        int cnt=0;
        for(int i=0;i<N;i++) if(S[i]==D[i]) cnt++;
        printf("%d\n",cnt);
    }
    return 0;
}

